package quota

import (
	"context"
	"fmt"
	"log/slog"
	"sync"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logfields"
)

// PolicyQuotaController enforces per-namespace limits on CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	log                  *slog.Logger
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace      int
	namespacePolicyCounts map[string]int
	mu                   sync.RWMutex
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	log *slog.Logger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPerNamespace:       maxPerNamespace,
		namespacePolicyCounts: make(map[string]int),
	}
}

// Run starts the controller loop that watches CiliumNetworkPolicy resources.
func (p *PolicyQuotaController) Run(ctx context.Context) error {
	p.log.Info("Starting PolicyQuotaController")

	for {
		select {
		case <-ctx.Done():
			p.log.Info("Stopping PolicyQuotaController")
			return ctx.Err()
		case event, ok := <-p.ciliumNetworkPolicies.Events(ctx):
			if !ok {
				return nil
			}

			switch event.Kind {
			case resource.Upsert:
				p.handleUpsert(event.Object)
			case resource.Delete:
				p.handleDelete(event.Object)
			case resource.Sync:
				p.log.Info("CiliumNetworkPolicy resources synchronized")
			}

			event.Done(nil)
		}
	}
}

// handleUpsert processes an upsert event for a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handleUpsert(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.GetNamespace()
	name := cnp.GetName()

	p.mu.Lock()
	defer p.mu.Unlock()

	// Increment the count for this namespace
	p.namespacePolicyCounts[namespace]++
	p.log.Debug("CiliumNetworkPolicy upserted",
		logfields.LogField{Key: "namespace", Value: namespace},
		logfields.LogField{Key: "name", Value: name},
		logfields.LogField{Key: "namespace_count", Value: p.namespacePolicyCounts[namespace]},
	)
}

// handleDelete processes a delete event for a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handleDelete(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.GetNamespace()
	name := cnp.GetName()

	p.mu.Lock()
	defer p.mu.Unlock()

	// Decrement the count for this namespace
	if count, exists := p.namespacePolicyCounts[namespace]; exists && count > 0 {
		p.namespacePolicyCounts[namespace]--
	}

	// Clean up empty entries
	if p.namespacePolicyCounts[namespace] == 0 {
		delete(p.namespacePolicyCounts, namespace)
	}

	p.log.Debug("CiliumNetworkPolicy deleted",
		logfields.LogField{Key: "namespace", Value: namespace},
		logfields.LogField{Key: "name", Value: name},
	)
}

// CheckQuota checks if a namespace has exceeded the policy quota.
// Returns an error if the quota is exceeded, nil otherwise.
func (p *PolicyQuotaController) CheckQuota(namespace string) error {
	if p.maxPerNamespace <= 0 {
		// 0 or negative means unlimited
		return nil
	}

	p.mu.RLock()
	defer p.mu.RUnlock()

	count := p.namespacePolicyCounts[namespace]
	if count >= p.maxPerNamespace {
		return fmt.Errorf("namespace %q has reached the maximum number of CiliumNetworkPolicies (%d)",
			namespace, p.maxPerNamespace)
	}

	return nil
}

// GetNamespaceCount returns the current count of CiliumNetworkPolicies in a namespace.
// This is useful for testing and monitoring purposes.
func (p *PolicyQuotaController) GetNamespaceCount(namespace string) int {
	p.mu.RLock()
	defer p.mu.RUnlock()

	return p.namespacePolicyCounts[namespace]
}

