	controller := NewPolicyQuotaController(log, mockRes, 10)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	controller.handleUpsert(cnp)

	count := controller.GetNamespaceCount("default")
	assert.Equal(t, 1, count)

	// Upsert another policy in the same namespace
	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "default",
		},
	}

