// TestHandleDelete tests policy count decrease on delete.
func TestHandleDelete(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 10)

	// Add a policy
	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	controller.handleUpsert(cnp)
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))

	// Delete the policy
	controller.handleDelete(cnp)
	assert.Equal(t, 0, controller.GetNamespaceCount("default"))
}

// TestMultipleNamespaces tests quota tracking across multiple namespaces.
func TestMultipleNamespaces(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 5)

	// Add policies to different namespaces
	cnp1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-1",
			Namespace: "default",
		},
	}

	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-2",
			Namespace: "kube-system",
		},
	}

	controller.handleUpsert(cnp1)
	controller.handleUpsert(cnp2)

	assert.Equal(t, 1, controller.GetNamespaceCount("default"))
	assert.Equal(t, 1, controller.GetNamespaceCount("kube-system"))

	// Add another policy to default namespace
	cnp3 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-3",
			Namespace: "default",
		},
	}

	controller.handleUpsert(cnp3)

	assert.Equal(t, 2, controller.GetNamespaceCount("default"))
	assert.Equal(t, 1, controller.GetNamespaceCount("kube-system"))

	// Check quota for each namespace
	err1 := controller.CheckQuota("default")
	assert.NoError(t, err1)

	err2 := controller.CheckQuota("kube-system")
	assert.NoError(t, err2)
}

// TestGetNamespaceCount tests GetNamespaceCount method.
func TestGetNamespaceCount(t *testing.T) {
