	assert.Equal(t, 0, controller.GetNamespaceCount("non-existent"))

	// Add a policy and verify count
	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	controller.handleUpsert(cnp)
	assert.Equal(t, 1, controller.GetNamespaceCount("default"))
}

// TestConcurrentOperations tests thread-safe operations.
func TestConcurrentOperations(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 100)

	// Simulate concurrent upserts and deletes
	done := make(chan bool, 10)

	for i := 0; i < 10; i++ {
		go func(id int) {
			for j := 0; j < 10; j++ {
				cnp := &cilium_v2.CiliumNetworkPolicy{
					ObjectMeta: metav1.ObjectMeta{
						Name:      "policy-" + string(rune(id)) + "-" + string(rune(j)),
						Namespace: "default",
					},
				}
				controller.handleUpsert(cnp)
			}
			done <- true
		}(i)
	}

	// Wait for all goroutines to complete
	for i := 0; i < 10; i++ {
		<-done
	}

	// Should have 100 policies
	assert.Equal(t, 100, controller.GetNamespaceCount("default"))

	// CheckQuota should succeed as we're at the limit
	err := controller.CheckQuota("default")
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "reached the maximum")
}

// TestDeleteNonExistentNamespace tests deleting from a non-existent namespace.
func TestDeleteNonExistentNamespace(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 10)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
	}

	// Should not panic when deleting from a namespace that doesn't exist in the map
	assert.NotPanics(t, func() {
		controller.handleDelete(cnp)
	})

	assert.Equal(t, 0, controller.GetNamespaceCount("default"))
}

// TestRunContext tests Run method with context cancellation.
func TestRunContext(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	eventsChan := make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy])
	mockRes := &mockResource{
		events: eventsChan,
	}

	controller := NewPolicyQuotaController(log, mockRes, 10)

	ctx, cancel := context.WithCancel(context.Background())

	done := make(chan error, 1)
	go func() {
		done <- controller.Run(ctx)
	}()

	// Cancel the context
	cancel()

	// Run should return the context error
	err := <-done
	require.Error(t, err)
	assert.Equal(t, context.Canceled, err)
}

