	mu                   sync.RWMutex
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	log *slog.Logger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPerNamespace:       maxPerNamespace,
		namespacePolicyCounts: make(map[string]int),
	}
}

// Run starts the controller loop that watches CiliumNetworkPolicy resources.
func (p *PolicyQuotaController) Run(ctx context.Context) error {
	p.log.Info("Starting PolicyQuotaController")

	for {
		select {
		case <-ctx.Done():
			p.log.Info("Stopping PolicyQuotaController")
			return ctx.Err()
		case event, ok := <-p.ciliumNetworkPolicies.Events(ctx):
			if !ok {
				return nil
			}

			switch event.Kind {
			case resource.Upsert:
				p.handleUpsert(event.Object)
			case resource.Delete:
				p.handleDelete(event.Object)
			case resource.Sync:
				p.log.Info("CiliumNetworkPolicy resources synchronized")
			}

			event.Done(nil)
		}
	}
}

// handleUpsert processes an upsert event for a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handleUpsert(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.GetNamespace()
	name := cnp.GetName()

	p.mu.Lock()
	defer p.mu.Unlock()

	// Increment the count for this namespace
	p.namespacePolicyCounts[namespace]++
	p.log.Debug("CiliumNetworkPolicy upserted",
		"namespace", namespace,
		"name", name,
		"namespace_count", p.namespacePolicyCounts[namespace],
	)
}

// handleDelete processes a delete event for a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handleDelete(cnp *cilium_v2.CiliumNetworkPolicy) {
	namespace := cnp.GetNamespace()
	name := cnp.GetName()

	p.mu.Lock()
	defer p.mu.Unlock()

	// Decrement the count for this namespace
	if count, exists := p.namespacePolicyCounts[namespace]; exists && count > 0 {
		p.namespacePolicyCounts[namespace]--
	}

	// Clean up empty entries
	if p.namespacePolicyCounts[namespace] == 0 {
		delete(p.namespacePolicyCounts, namespace)
	}

	p.log.Debug("CiliumNetworkPolicy deleted",
		"namespace", namespace,
		"name", name,
