	}

	p.mu.RLock()
	defer p.mu.RUnlock()

	count := p.namespacePolicyCounts[namespace]
	if count >= p.maxPerNamespace {
		return fmt.Errorf("namespace %q has reached the maximum number of CiliumNetworkPolicies (%d)",
