// TestNewPolicyQuotaController tests controller creation.
func TestNewPolicyQuotaController(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 10)

	assert.NotNil(t, controller)
	assert.Equal(t, 10, controller.maxPerNamespace)
	assert.NotNil(t, controller.namespacePolicyCounts)
}

// TestCheckQuotaUnlimited tests CheckQuota with unlimited quota.
func TestCheckQuotaUnlimited(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 0)

	// With unlimited quota (0), any namespace should be allowed
	err := controller.CheckQuota("default")
	assert.NoError(t, err)

	err = controller.CheckQuota("kube-system")
	assert.NoError(t, err)
}

// TestCheckQuotaExceeded tests CheckQuota when quota is exceeded.
func TestCheckQuotaExceeded(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 5)

	// Manually set the namespace policy count to simulate policies already existing
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 5
	controller.mu.Unlock()

	// CheckQuota should fail when at the limit
	err := controller.CheckQuota("default")
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "reached the maximum")
	assert.Contains(t, err.Error(), "default")
}

// TestCheckQuotaNotExceeded tests CheckQuota when quota is not exceeded.
func TestCheckQuotaNotExceeded(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 5)

	// Manually set the namespace policy count below the limit
	controller.mu.Lock()
	controller.namespacePolicyCounts["default"] = 3
	controller.mu.Unlock()

	// CheckQuota should succeed when below the limit
	err := controller.CheckQuota("default")
	assert.NoError(t, err)
}

// TestHandleUpsert tests policy count increase on upsert.
func TestHandleUpsert(t *testing.T) {
	log := slog.New(slog.NewTextHandler(nil, nil))
