		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy-2",
			Namespace: "default",
		},
	}

	controller.handleUpsert(cnp2)

	count = controller.GetNamespaceCount("default")
	assert.Equal(t, 2, count)
}

